// Event Bus and Event Handlers

public interface IEvent
{
    Guid AggregateId { get; }
}

public interface IEventHandler<TEvent> where TEvent : IEvent
{
    void Handle(TEvent @event);
}

public class EventBus : IEventBus
{
    private readonly Dictionary<Type, List<IEventHandlerWrapper>> _eventHandlers;

    public EventBus()
    {
        _eventHandlers = new Dictionary<Type, List<IEventHandlerWrapper>>();
    }

    public void Publish<TEvent>(TEvent @event) where TEvent : IEvent
    {
        if (_eventHandlers.TryGetValue(@event.GetType(), out var handlers))
        {
            foreach (var handler in handlers)
            {
                handler.Handle(@event);
            }
        }
    }

    public void Subscribe<TEvent, TEventHandler>() where TEvent : IEvent where TEventHandler : IEventHandler<TEvent>
    {
        var eventType = typeof(TEvent);
        if (!_eventHandlers.ContainsKey(eventType))
        {
            _eventHandlers[eventType] = new List<IEventHandlerWrapper>();
        }

        if (!_eventHandlers[eventType].Any(x => x.HandlerType == typeof(TEventHandler)))
        {
            _eventHandlers[eventType].Add(new EventHandlerWrapper<TEvent>());
        }
    }

    private interface IEventHandlerWrapper
    {
        Type HandlerType { get; }
        void Handle(IEvent @event);
    }

    private class EventHandlerWrapper<TEvent> : IEventHandlerWrapper where TEvent : IEvent
    {
        public Type HandlerType => typeof(IEventHandler<TEvent>);

        public void Handle(IEvent @event)
        {
            var handler = (IEventHandler<TEvent>)DependencyResolver.GetService(typeof(IEventHandler<TEvent>));
            handler.Handle((TEvent)@event);
        }
    }
}


